// Select email template based on signal type and ICP tier
const body = $input.first().json.body || $input.first().json;
const signal = typeof body.signal === 'string' ? JSON.parse(body.signal) : body.signal || body;
const dealId = body.deal_id || null;

// Template map: signal_type → template ID and campaign
const TEMPLATE_MAP = {
  GITHUB_RL_REPO: {
    template_id: 'github-rl-cold-v2',
    campaign_id: $vars.INSTANTLY_CAMPAIGN_GITHUB || 'campaign-github-rl',
    subject_hint: 'Infrastructure at {company}',
    angle: 'github_activity'
  },
  ARXIV_PAPER: {
    template_id: 'research-lab-cold-v1',
    campaign_id: $vars.INSTANTLY_CAMPAIGN_ARXIV || 'campaign-arxiv-labs',
    subject_hint: 'Scaling {company}\'s research',
    angle: 'research_publication'
  },
  JOB_POSTING: {
    template_id: 'hiring-signal-cold-v1',
    campaign_id: $vars.INSTANTLY_CAMPAIGN_JOBS || 'campaign-hiring-signal',
    subject_hint: 'Re: {company} infra hiring',
    angle: 'hiring_intent'
  },
  HUGGINGFACE_MODEL: {
    template_id: 'hf-model-cold-v1',
    campaign_id: $vars.INSTANTLY_CAMPAIGN_HF || 'campaign-hf-models',
    subject_hint: 'Training infra for {company}',
    angle: 'model_upload'
  },
  FUNDING_EVENT: {
    template_id: 'funded-cold-v1',
    campaign_id: $vars.INSTANTLY_CAMPAIGN_FUNDING || 'campaign-funded-cos',
    subject_hint: 'Congrats on the round — infra',
    angle: 'funding_event'
  }
};

const templateConfig = TEMPLATE_MAP[signal.signal_type] || TEMPLATE_MAP['GITHUB_RL_REPO'];

// A/B variant selection: rotate 1/3 each
const variants = ['A', 'B', 'C'];
const variantIndex = Math.abs(
  (signal.company_name || 'unknown').split('').reduce((acc, c) => acc + c.charCodeAt(0), 0)
) % 3;
const selected_variant = variants[variantIndex];

return [{
  json: {
    signal,
    deal_id: dealId,
    template_config: templateConfig,
    selected_variant,
    contacts: signal.contacts || [],
    company_name: signal.company_name || 'Unknown',
    company_domain: signal.company_domain || '',
    icp_score: signal.icp_score || 'B',
    prepared_at: new Date().toISOString()
  }
}];

