parameters.jsCode:
// Parse LLM response and select variant copy
const templateData = $('Select Template').first().json;
const llmResponse = $input.first().json;

let emailCopy;
try {
  const content = llmResponse?.content?.[0]?.text || '{}';
  // Strip markdown code fences if present
  const cleaned = content.replace(/^```json\n?|```$/gm, '').trim();
  emailCopy = JSON.parse(cleaned);
} catch (e) {
  emailCopy = {
    subject: `Infrastructure at ${templateData.company_name}`,
    body: `Hi,\n\nI noticed ${templateData.company_name} is actively scaling its training infrastructure. We help teams like yours reduce training iteration time.\n\nWould a quick comparison of your current setup be useful?`,
    cta: 'Worth a 15-min chat?'
  };
}

// Build per-contact payloads
const contacts = templateData.contacts || [];
const payloads = contacts.map(contact => ({
  ...templateData,
  contact,
  email_copy: {
    subject: emailCopy.subject.replace('{company}', templateData.company_name),
    body: emailCopy.body
      .replace('{first_name}', contact.first_name || 'there')
      .replace('{company}', templateData.company_name),
    cta: emailCopy.cta
  },
  email_generated_at: new Date().toISOString()
}));

if (payloads.length === 0) {
  return [{ json: { ...templateData, email_copy: emailCopy, contacts: [], skipped: true, reason: 'no_verified_contacts' } }];
}

return payloads.map(p => ({ json: p }));

